  <text x="20" y="34" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Naver Financial × Dunamu Merger — How the Deadline Kept Slipping</text>
  <g font-family="sans-serif">
    <line x1="60" y1="330" x2="660" y2="330" stroke="#3f3f46" stroke-width="2"/>
    <circle cx="100" cy="330" r="7" fill="#71717a"/>
    <text x="100" y="360" fill="#e4e4e7" font-size="13" text-anchor="middle">Nov 2024</text>
